    /**
     * Generate PDF file from template data.
     *
     * @return array ['success' => true, 'filename' => '...', 'path' => '...'] or ['error' => '...']
     */
    public function generate(array $data): array
    {
        $html = $this->renderHtml($data);

        // Ensure directories exist
        $pdfDir = storage_path('app/pdfs');
        $tmpDir = storage_path('app/tmp');
        if (! is_dir($pdfDir)) {
            mkdir($pdfDir, 0755, true);
        }
        if (! is_dir($tmpDir)) {
            mkdir($tmpDir, 0755, true);
        }

        $safeName = preg_replace('/[^a-zA-Z0-9_\-]/', '_', $data['customerName']);
        $now = now();
        $filename = 'Loan_Proposal_' . $safeName . '_' . $now->format('Y-m-d') . '_' . $now->format('H_i_s') . '.pdf';
        $filepath = $pdfDir . '/' . $filename;

        // Write HTML to temp file
        $tmpHtml = $tmpDir . '/pdf_' . uniqid() . '.html';
        file_put_contents($tmpHtml, $html);

        // Generate PDF — three-tier strategy:
        // 1. PDF_USE_MICROSERVICE=true → microservice only (escape hatch)
        // 2. Chrome available → Chrome headless directly (fastest)
        // 3. Chrome unavailable → microservice fallback
        $error = null;

        if (config('app.pdf_use_microservice')) {
            $error = $this->generateWithMicroservice($html, $filepath);
            @unlink($tmpHtml);
        } elseif ($this->isChromeAvailable()) {
            $error = $this->generateWithChrome($tmpHtml, $filepath);
            if ($error !== null && config('app.pdf_service_url')) {
                Log::warning('Chrome PDF failed, falling back to microservice', $error);
                $error = $this->generateWithMicroservice($html, $filepath);
            }
        } else {
            $error = $this->generateWithMicroservice($html, $filepath);
            @unlink($tmpHtml);
        }

        if ($error !== null) {
            return $error;
        }

        return [
            'success' => true,
            'filename' => $filename,
            'path' => $filepath,
        ];
    }

    /**
     * Check if Chrome headless can be used: exec() enabled + Chrome binary found.
     */
    private function isChromeAvailable(): bool
    {
        if (!function_exists('exec')) {
            return false;
        }

        $disabled = array_map('trim', explode(',', ini_get('disable_functions') ?: ''));
        if (in_array('exec', $disabled, true)) {
            return false;
        }

        $chromePath = $this->getChromePath();

        if (file_exists($chromePath)) {
            return true;
        }

        // On Linux, bare names like 'google-chrome' won't pass file_exists — check PATH
        if (PHP_OS_FAMILY !== 'Windows') {
            exec('command -v ' . escapeshellarg($chromePath) . ' 2>/dev/null', $output, $exitCode);

            return $exitCode === 0;
        }

        return false;
    }

    /**
     * Generate PDF using Chrome headless.
     *
     * @return array|null null on success, error array on failure
     */
    private function generateWithChrome(string $tmpHtml, string $filepath): ?array
    {
        $chromePath = $this->getChromePath();
        $profileDir = sys_get_temp_dir() . DIRECTORY_SEPARATOR . 'shf_chrome_' . uniqid();

        if (PHP_OS_FAMILY === 'Windows') {
            $cmd = '"' . $chromePath . '"'
                . ' --headless --disable-gpu --no-sandbox --disable-software-rasterizer'
                . ' --run-all-compositor-stages-before-draw'
                . ' --user-data-dir="' . str_replace('/', '\\', $profileDir) . '"'
                . ' --print-to-pdf="' . str_replace('/', '\\', $filepath) . '"'
                . ' --no-pdf-header-footer'
                . ' "' . str_replace('/', '\\', $tmpHtml) . '"'
                . ' 2>&1';
        } else {
            $cmd = escapeshellarg($chromePath)
                . ' --headless --disable-gpu --no-sandbox --disable-software-rasterizer'
                . ' --run-all-compositor-stages-before-draw'
                . ' --user-data-dir=' . escapeshellarg($profileDir)
                . ' --print-to-pdf=' . escapeshellarg($filepath)
                . ' --no-pdf-header-footer'
                . ' ' . escapeshellarg($tmpHtml)
                . ' 2>&1';
        }

        Log::info('Chrome PDF command', ['cmd' => $cmd]);
        exec($cmd, $output, $exitCode);
        @unlink($tmpHtml);
        $this->removeDirectory($profileDir);

        // On Windows, give Chrome a moment to flush the file
        if (PHP_OS_FAMILY === 'Windows' && $exitCode === 0 && ! file_exists($filepath)) {
            usleep(500000); // 500ms
        }

        if (! file_exists($filepath)) {
            $errMsg = implode("\n", $output ?? []);
            Log::error('Chrome PDF generation failed', [
                'exit_code' => $exitCode,
                'output' => $errMsg,
                'filepath' => $filepath,
                'filepath_exists' => file_exists($filepath),
                'dir_contents' => glob(dirname($filepath) . '/*'),
            ]);

            return ['error' => 'PDF generation failed (exit code ' . $exitCode . '): ' . $errMsg];
        }

        return null;
    }

    /**
     * Generate PDF via cURL to a PDF microservice.
     *
     * @return array|null null on success, error array on failure
     */
    private function generateWithMicroservice(string $html, string $filepath): ?array
    {
        $pdfServiceUrl = config('app.pdf_service_url', 'http://127.0.0.1:3000/pdf');
        $pdfServiceKey = config('app.pdf_service_key', '');

        $headers = ['Content-Type: application/json'];
        if ($pdfServiceKey) {
            $headers[] = 'X-API-Key: ' . $pdfServiceKey;
        }

        $ch = curl_init($pdfServiceUrl);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode(['html' => $html]));
        curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 5);
        curl_setopt($ch, CURLOPT_TIMEOUT, 60);

        $pdf = curl_exec($ch);
        $curlError = curl_error($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);

        if ($pdf === false || $httpCode !== 200 || empty($pdf)) {
            Log::error('PDF microservice failed', [
                'http_code' => $httpCode,
                'curl_error' => $curlError,
                'url' => $pdfServiceUrl,
            ]);

            return ['error' => 'PDF generation failed: ' . ($curlError ?: 'HTTP ' . $httpCode)];
        }

        file_put_contents($filepath, $pdf);

        if (!file_exists($filepath)) {
            return ['error' => 'PDF generation failed: could not write file'];
        }

        return null;
    }

    /**
     * Recursively remove a directory.
     */
    /**
     * Recursively remove a directory.
     */
    private function removeDirectory(string $dir): void
    {
        if (! is_dir($dir)) {
            return;
        }
        $items = new \RecursiveIteratorIterator(
            new \RecursiveDirectoryIterator($dir, \FilesystemIterator::SKIP_DOTS),
            \RecursiveIteratorIterator::CHILD_FIRST
        );
        foreach ($items as $item) {
            $item->isDir() ? @rmdir($item->getPathname()) : @unlink($item->getPathname());
        }
        @rmdir($dir);
    }

    /**
     * Auto-detect Chrome/Chromium path per OS.
     */
    private function getChromePath(): string
    {
        $configured = config('app.chrome_path');
        if ($configured && file_exists($configured)) {
            return $configured;
        }

        if (PHP_OS_FAMILY === 'Windows') {
            $candidates = [
                'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe',
                'C:\\Program Files (x86)\\Google\\Chrome\\Application\\chrome.exe',
            ];
            foreach ($candidates as $p) {
                if (file_exists($p)) return $p;
            }
            return 'chrome';
        }

        // Linux / macOS
        $candidates = [
            '/usr/bin/google-chrome',
            '/usr/bin/google-chrome-stable',
            '/usr/bin/chromium-browser',
            '/usr/bin/chromium',
            '/snap/bin/chromium',
        ];
        foreach ($candidates as $p) {
            if (file_exists($p)) return $p;
        }
        return 'google-chrome';
    }

