                $html .= '<th>' . $e($T['documentName']) . '</th></tr>';
                foreach ($chunk as $i => $doc) {
                    $globalIdx = $docOffset + $i;
                    $alt = ($globalIdx % 2 === 1) ? ' class="alt"' : '';
                    $biName = $e($doc['en']);
                    if (!empty($doc['gu'])) $biName .= ' / ' . $e($doc['gu']);
                    $html .= '<tr' . $alt . '><td style="text-align:center;">' . ($globalIdx + 1) . '</td>';
                    $html .= '<td>' . $biName . '</td></tr>';
                }
                $html .= '</table>';
                $docOffset += count($chunk);
            }
        }

        // New page for EMI
        $html .= '</div></td></tr></tbody></table>';
        $html .= '<table class="page-wrapper" style="page-break-before: always;"><thead><tr><td></td></tr></thead>';
        $html .= '<tfoot><tr><td></td></tr></tfoot>';
        $html .= '<tbody><tr><td><div class="content">';

        // EMI Tables
        $emiIndex = 0;
        foreach ($data['tenures'] as $tenure) {
            if ($emiIndex > 0 && $emiIndex % 2 === 0) {
                $html .= '</div></td></tr></tbody></table>';
                $html .= '<table class="page-wrapper" style="page-break-before: always;"><thead><tr><td></td></tr></thead>';
                $html .= '<tfoot><tr><td></td></tr></tfoot>';
                $html .= '<tbody><tr><td><div class="content">';
            }
            $html .= '<div class="section-header emi">' . $e($tenure . ' ' . $T['years'] . ' - ' . $T['emiComparison']) . '</div>';
            $html .= '<table class="data-table"><tr><th style="width:' . $descW . ';">' . $e($T['description']) . '</th>';
            foreach ($data['banks'] as $bank) {
                $html .= '<th class="bank-col" style="width:' . $bankColW . ';">' . $e($bank['name']) . '</th>';
            }
            $html .= '</tr>';

            // ROI
            $html .= '<tr><td>' . $e($T['roi']) . '</td>';
            foreach ($data['banks'] as $bank) {
                $roiStr = number_format($bank['roiMin'], 2) . '%';
                if ($bank['roiMax'] > 0) $roiStr = number_format($bank['roiMin'], 2) . '% - ' . number_format($bank['roiMax'], 2) . '%';
                $html .= '<td class="bank-val">' . $e($roiStr) . '</td>';
            }
            $html .= '</tr>';

            // Monthly EMI
            $html .= '<tr class="alt"><td>' . $e($T['monthlyEmi']) . '</td>';
            foreach ($data['banks'] as $bank) {
                $emi = $bank['emiByTenure'][$tenure] ?? null;
                $html .= '<td class="bank-val">' . $e($emi ? NumberToWordsService::formatCurrency($emi['emi']) : '–') . '</td>';
            }
            $html .= '</tr>';

            // Total Interest
            $html .= '<tr><td>' . $e($T['totalInterest']) . '</td>';
            foreach ($data['banks'] as $bank) {
                $emi = $bank['emiByTenure'][$tenure] ?? null;
                $html .= '<td class="bank-val">' . $e($emi ? NumberToWordsService::formatCurrency($emi['totalInterest']) : '–') . '</td>';
            }
            $html .= '</tr>';

            // Total Payment
            $html .= '<tr class="alt"><td>' . $e($T['totalPayment']) . '</td>';
            foreach ($data['banks'] as $bank) {
                $emi = $bank['emiByTenure'][$tenure] ?? null;
                $html .= '<td class="bank-val">' . $e($emi ? NumberToWordsService::formatCurrency($emi['totalPayment']) : '–') . '</td>';
            }
            $html .= '</tr></table>';
            $emiIndex++;
        }

        // New page for Charges
        $html .= '</div></td></tr></tbody></table>';
        $html .= '<table class="page-wrapper" style="page-break-before: always;"><thead><tr><td></td></tr></thead>';
        $html .= '<tfoot><tr><td></td></tr></tfoot>';
        $html .= '<tbody><tr><td><div class="content">';

        // Charges Table
        $html .= '<div class="section-header charges">' . $e($T['chargesComparison']) . '</div>';
        $html .= '<table class="data-table"><tr><th style="width:' . $descW . ';">' . $e($T['chargeDesc']) . '</th>';
        foreach ($data['banks'] as $bank) {
            $html .= '<th class="bank-col" style="width:' . $bankColW . ';">' . $e($bank['name']) . '</th>';
        }
        $html .= '</tr>';

        $chargeRows = [
            ['key' => 'pf', 'label' => $T['pfCharge']],
            ['key' => 'admin', 'label' => $T['adminCharges']],
            ['key' => 'stamp_notary', 'label' => $T['stampDuty']],
            ['key' => 'iom', 'label' => $T['iomCharges']],
            ['key' => 'registration_fee', 'label' => $T['notaryCharges']],
            ['key' => 'advocate', 'label' => $T['advocateFees']],
            ['key' => 'tc', 'label' => $T['tcReport']],
        ];

        $filteredRows = [];
        foreach ($chargeRows as $cr) {
            $hasValue = false;
            foreach ($data['banks'] as $bank) {
                if (!empty($bank['charges'][$cr['key']])) {
                    $hasValue = true;
                    break;
                }
            }
            if ($hasValue) $filteredRows[] = $cr;
        }

        $extraNames = [];
        foreach ($data['banks'] as $bank) {
            $c = $bank['charges'];
            if (!empty($c['extra1Name']) && !in_array($c['extra1Name'], $extraNames)) $extraNames[] = $c['extra1Name'];
            if (!empty($c['extra2Name']) && !in_array($c['extra2Name'], $extraNames)) $extraNames[] = $c['extra2Name'];
        }

        $rowIdx = 0;
        foreach ($filteredRows as $cr) {
            $alt = ($rowIdx % 2 === 1) ? ' class="alt"' : '';
            $html .= '<tr' . $alt . '><td>' . $e($cr['label']) . '</td>';
            foreach ($data['banks'] as $bank) {
                $val = $bank['charges'][$cr['key']] ?? 0;
                $html .= '<td class="bank-val">' . ($val ? $e(NumberToWordsService::formatCurrency($val)) : '–') . '</td>';
            }
            $html .= '</tr>';
            $rowIdx++;
        }

        foreach ($extraNames as $name) {
            $alt = ($rowIdx % 2 === 1) ? ' class="alt"' : '';
            $html .= '<tr' . $alt . '><td>' . $e($name) . '</td>';
            foreach ($data['banks'] as $bank) {
                $c = $bank['charges'];
                $val = 0;
                if (($c['extra1Name'] ?? '') === $name && !empty($c['extra1Amt'])) $val = $c['extra1Amt'];
                elseif (($c['extra2Name'] ?? '') === $name && !empty($c['extra2Amt'])) $val = $c['extra2Amt'];
                $html .= '<td class="bank-val">' . ($val ? $e(NumberToWordsService::formatCurrency($val)) : '–') . '</td>';
            }
            $html .= '</tr>';
            $rowIdx++;
        }

        // Total row
        $html .= '<tr class="total-row"><td><strong>' . $e($T['totalCharges']) . '</strong></td>';
        foreach ($data['banks'] as $bank) {
            $html .= '<td class="bank-val"><strong>' . $e(NumberToWordsService::formatCurrency($bank['charges']['total'])) . '</strong></td>';
        }
        $html .= '</tr></table>';

        // Additional Notes
        if (!empty($data['additionalNotes'])) {
            $html .= '<div class="additional-notes">';
            $html .= '<div class="notes-title">' . $e($T['additionalNotes']) . '</div>';
            $html .= nl2br($e($data['additionalNotes']));
            $html .= '</div>';
        }

        $html .= '</div></td></tr></tbody></table>';
        $html .= '</body></html>';

        return $html;
    }
}
